mapper.select:
select

from t_payment_record

    is_deleted = 0

        and id = #{id}


        and user_id = #{userId}


        and CAST(user_id AS CHAR CHARACTER SET utf8mb4) COLLATE utf8mb4_general_ci in (select CAST(id AS CHAR CHARACTER SET utf8mb4) COLLATE utf8mb4_general_ci from t_member where idno COLLATE utf8mb4_general_ci = CAST(#{idno} AS CHAR CHARACTER SET utf8mb4) COLLATE utf8mb4_general_ci)


        and transaction_number like concat('%', #{transactionNumber}, '%')


        and partner_number like concat('%', #{partnerNumber}, '%')


        and payment_address like concat('%', #{paymentAddress}, '%')


        and receiving_address like concat('%', #{receivingAddress}, '%')


        and payment_status = #{paymentStatus}


        and create_time >= #{createTimeStart}


        and create_time <= #{createTimeEnd}



    order by ${orderBy}


    order by create_time desc


    limit #{pageNo}, #{pageSize}

select count(1)
from t_payment_record

    is_deleted = 0

        and id = #{id}


        and user_id = #{userId}


        and transaction_number like concat('%', #{transactionNumber}, '%')


        and partner_number like concat('%', #{partnerNumber}, '%')


        and payment_address like concat('%', #{paymentAddress}, '%')


        and receiving_address like concat('%', #{receivingAddress}, '%')


        and payment_status = #{paymentStatus}


        and create_time >= #{createTimeStart}


        and create_time <= #{createTimeEnd}

select ifnull(sum(amount), 0)
from t_payment_record

    is_deleted = 0
    and payment_status = 1

        and id = #{id}


        and user_id = #{userId}


        and transaction_number like concat('%', #{transactionNumber}, '%')


        and partner_number like concat('%', #{partnerNumber}, '%')


        and payment_address like concat('%', #{paymentAddress}, '%')


        and receiving_address like concat('%', #{receivingAddress}, '%')


        and payment_status = #{paymentStatus}


        and create_time >= #{createTimeStart}


        and create_time <= #{createTimeEnd}
